output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?team ?teamLabel ?city ?cityLabel ?population ?stadium ?stadiumLabel WHERE {
  ?team wdt:P118 wd:Q155223 .
  ?team wdt:P159 ?city .
  ?city wdt:P1082 ?population .
  ?team wdt:P115 ?stadium .
  OPTIONAL {
    ?team rdfs:label ?teamLabel
    FILTER(lang(?teamLabel) = 'en')
  }
  OPTIONAL {
    ?city rdfs:label ?cityLabel
    FILTER(lang(?cityLabel) = 'en')
  }
  OPTIONAL {
    ?stadium rdfs:label ?stadiumLabel
    FILTER(lang(?stadiumLabel) = 'en')
  }
}
LIMIT 30
